(async () => {
  const reserved = new Set(['home', 'explore', 'notifications', 'messages', 'settings', 'compose', 'search', 'i']);
  const normalizeUser = (value) => {
    let user = String(value || '').trim();
    if (!user) return '';
    user = user.replace(/^@/, '');
    user = user.replace(/^https?:\/\/(?:www\.)?x\.com\//i, '');
    user = user.replace(/^\/+/, '');
    user = user.split('/')[0] || '';
    if (!/^[A-Za-z0-9_]{1,15}$/.test(user)) return '';
    if (reserved.has(user.toLowerCase())) return '';
    return user;
  };

  let targetUser = normalizeUser(${{ args.user | json }});
  if (!targetUser) {
    const resolveUser = () => {
      const profileHref = document.querySelector('a[data-testid="AppTabBar_Profile_Link"]')?.getAttribute('href');
      const fromProfileLink = normalizeUser(profileHref);
      if (fromProfileLink) return fromProfileLink;

      const switcherText = document.querySelector('[data-testid="SideNav_AccountSwitcher_Button"]')?.textContent || '';
      const switcherMatch = switcherText.match(/@([A-Za-z0-9_]{1,15})/);
      const fromSwitcher = normalizeUser(switcherMatch?.[1]);
      if (fromSwitcher) return fromSwitcher;

      for (const link of document.querySelectorAll('header a[href^="/"], nav a[href^="/"], aside a[href^="/"]')) {
        const fromNav = normalizeUser(link.getAttribute('href'));
        if (fromNav) return fromNav;
      }

      return '';
    };

    for (let i = 0; i < 10 && !targetUser; i += 1) {
      targetUser = resolveUser();
      if (!targetUser) await new Promise(r => setTimeout(r, 1000));
    }
  }

  if (!targetUser) throw new Error('Could not find logged-in user');
  window.location.href = 'https://x.com/' + targetUser + '/following';
})()

(() => {
  const results = [];
  const seen = new Set();
  const cells = document.querySelectorAll('[data-testid="UserCell"]');
  const cleanBio = (text) => (text || '').replace(/^Click to (?:Follow|Unfollow)\s+\S+\s*/i, '').trim().substring(0, 80);

  cells.forEach(cell => {
    try {
      const link = cell.querySelector('a[href^="/"]');
      const username = link?.getAttribute('href')?.replace('/', '') || '';
      if (!username || seen.has(username)) return;
      seen.add(username);

      const nameEl = cell.querySelector('[dir="ltr"]');
      const name = nameEl ? nameEl.textContent : '';
      const bioEl = cell.querySelector('[dir="auto"]');
      const bio = cleanBio(bioEl ? bioEl.textContent : '');

      results.push({ screen_name: username, name, bio, followers: 0 });
    } catch (e) {}
  });

  return results;
})()
